package com.google.gson;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "com.google.gson.steps"
)
public class CucumberTest {
}

package com.google.gson.steps;

import com.google.gson.Gson;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.junit.Assert;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class StepDefs {

    private Object targetObject;
    private Exception operationException;

    // Generic class "Foo<S, T>"
    public static class Foo<S, T> {
        private final S someSField;
        private final T someTField;
        public final Map<S, List<T>> map = new HashMap<S, List<T>>();

        public Foo(S sValue, T tValue) {
            this.someSField = sValue;
            this.someTField = tValue;
        }
    }

    // Concrete subclass "Bar" extends "Foo<String, Integer>"
    public static class Bar extends Foo<String, Integer> {
        public Bar() {
            super("", 0);
        }

        public Bar(String s, Integer i) {
            super(s, i);
        }
    }

    @Given("a generic class {string} defining fields of type {string} and {string}")
    public void a_generic_class_defining_fields(String className, String type1, String type2) {
        // Defined statically above
    }

    @Given("a concrete subclass {string} that extends {string}")
    public void a_concrete_subclass_that_extends(String subClass, String superClass) {
        // Defined statically above
        if (subClass.equals("Bar")) {
            targetObject = new Bar("someString", 1);
        }
    }

    @When("the system attempts to resolve the actual type of the fields inherited by {string}")
    public void the_system_attempts_to_resolve_types(String className) {
        try {
            Gson gson = new Gson();
            // This triggers TypeInfoFactory.getTypeInfoForField which calls getActualType
            String json = gson.toJson(targetObject);
        } catch (Exception e) {
            operationException = e;
        }
    }

    @Then("the type variable {string} should be resolved to {string}")
    public void the_type_variable_should_be_resolved_to(String typeVar, String typeResolved) {
        // If the operation succeeded, it means resolution worked.
        // We verify that no exception occurred in the next step.
        // Or if we want to be strict:
        if ("S".equals(typeVar)) {
             // Implicitly verified by success
        }
    }

    @Then("the operation should complete without throwing an {string}")
    public void the_operation_should_complete_without_throwing_an(String exceptionName) {
        if (operationException != null) {
            if (operationException.getClass().getSimpleName().equals(exceptionName)) {
                 Assert.fail("Threw " + exceptionName + ": " + operationException.getMessage());
            } else {
                 // Re-throw if it's a different exception
                 throw new RuntimeException(operationException);
            }
        }
    }
}
